#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N,K; long long S; scanf("%d %d %lld",&N,&K,&S);
        long long x=S; int *B=calloc(N,sizeof(int));
        int ok=1;
        for(int i=0;i<N;i++){
            long long r = ((x%K)+K)%K;
            int d=0;
            if(r==0) d=0;
            else if(r==1) d=1;
            else if(r==K-1) d=-1;
            else {ok=0; break;}
            B[i]=d;
            x = (x - d)/K;
        }
        if(ok && x==0){
            for(int i=0;i<N;i++){
                if(i) printf(" ");
                printf("%d",B[i]);
            }
            printf("\n");
        }else{
            printf("-2\n");
        }
        free(B);
    }
    return 0;
}

