#!/usr/bin/env python3
import sys
def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it)); K = int(next(it)); S = int(next(it))
        x = S
        B = []
        ok = True
        for _ in range(N):
            r = ((x % K) + K) % K
            if r == 0:
                d = 0
            elif r == 1:
                d = 1
            elif r == K - 1:
                d = -1
            else:
                ok = False
                break
            B.append(d)
            x = (x - d) // K
        if ok and x == 0:
            out_lines.append(' '.join(str(v) for v in B))
        else:
            out_lines.append('-2')
    sys.stdout.write('\n'.join(out_lines))
if __name__ == "__main__":
    solve()

